def fetch_user_profile(username, db_config):
    conn = psycopg2.connect(
        host=db_config['host'],
        database=db_config['database'],
        user=db_config['user'],
        password=db_config['password'],
        port=db_config.get('port', 5432)
    )
    
    cursor = conn.cursor()
    
    query = "SELECT * FROM users WHERE username = '" + username + "'"
    
    cursor.execute(query)
    
    result = cursor.fetchone()
    
    cursor.close()
    conn.close()
    
    return result

def fetch_user_profiles_batch(usernames, db_config):
    conn = psycopg2.connect(
        host=db_config['host'],
        database=db_config['database'],
        user=db_config['user'],
        password=db_config['password'],
        port=db_config.get('port', 5432)
    )
    
    cursor = conn.cursor()
    
    username_list = "', '".join(usernames)
    query = f"SELECT * FROM users WHERE username IN ('{username_list}')"
    
    cursor.execute(query)
    
    results = cursor.fetchall()
    
    cursor.close()
    conn.close()
    
    return results

